var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"……미나 양, 미나 양?","JPN":"……ミナさん、ミナさん？","ENG":"...Mina. Mina?","TWN":"……米娜？米娜？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아카데미 페스타에 다녀오시더니 꽤 피곤하셨나 보네요.","JPN":"アカデミーフェスタから帰ってきて、ずいぶんお疲れのようですね。","ENG":"My, you look exhausted after coming back from the Academy festival.","TWN":"你從學園祭回來後好像很累呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 선배? 내가 깜박 잠 들었나?","JPN":"ううん……先輩？　私、寝落ちしてた？","ENG":"Mm... Shiyoon? Did I fall asleep?","TWN":"嗯嗯，前輩？我睡著了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 페스타는 어떠셨어요?","JPN":"はい。それで、フェスタはどうでしたか？","ENG":"So? How was the festival?","TWN":"學園祭好玩嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마 또 지난여름처럼 유람선 갑판 청소만 실컷 하고 온 건 아니죠?","JPN":"まさか、また去年の夏のようにクルーズの掃除ばかりしてきたんじゃないですよね？","ENG":"You didn't just mop the deck like last summer, did you?","TWN":"你應該不會又跟去年夏天一樣，只有在船上打掃甲板吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"에이…… 설마 또 발렌타인 행사 때처럼 강제 노동을 한 건 아닐 거고요.","JPN":"それとも……前のバレンタインの時みたいに\\n強制労働でもさせられたわけではありませんよね？","ENG":"Or... I'm sure you didn't do forced labor like you did on Valentine’s Day.","TWN":"真是的……不會又像之前情人節活動那樣逼你做苦工吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배…… 혹시 아카데미 페스타에 왔었어?","JPN":"先輩……もしかしてアカデミーフェスタに来てた？","ENG":"Shiyoon... Were you at the festival?","TWN":"前輩……你有去學園祭嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리에요, 미나 양이 <color=#ffd34c>출장</color>간 동안 제가 미나 양의 몫까지 얼마나 열심히 일했는 줄 아세요?","JPN":"何を言っているんですか？\\nミナさんが<color=#ffd34c>出張</color>中に僕がミナさんの分までどれだけ働かされたのか、わかってないようですね。","ENG":"What are you talking about, Mina? While you were on your <color=#ffd34c>business trip</color>, I worked my butt off, doing your share of the work too.","TWN":"你在胡說什麼，米娜？你<color=#ffd34c>出差</color>的這段時間，你知道\\n我有多認真上班嗎？還連你的份都一起認真欸。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 기분 탓인가?","JPN":"そう？　気のせいかな……","ENG":"Really? Maybe I'm imagining things.","TWN":"是嗎？是我想太多了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음? 주머니 속에 뭔가가…….","JPN":"うん？　ポケットの中に何かが……","ENG":"Hmm? There's something in my pocket...","TWN":"嗯？口袋裡好像有東西……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 뭐지?","JPN":"これはなんだろう？","ENG":"What's this?","TWN":"這是什麼？"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 체스의 킹인 것 같은데요. 꽤 특이하게 생긴 물건이네요?","JPN":"チェスのキングのようですね。かなり変わった形の駒ですね。","ENG":"It appears to be the king piece in chess. But it looks quite peculiar, no?","TWN":"這好像是西洋棋裡的國王，長得好特別喔。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"체스의 킹이라고? 왜 이런 게 내 주머니에…….","JPN":"チェスのキング？　なぜこんなものが私のポケットに……","ENG":"The king? Why was this in my pocket...?","TWN":"西洋棋裡的國王？這怎麼會在我口袋裡……"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요? 저한테 그런 걸 물어보셔도 곤란한데요.","JPN":"さあ。僕に聞かれても。","ENG":"Don't ask me. If anyone knows, it should be you.","TWN":"我也不知道，這個問題不應該問我吧。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마도 누군가에게 선물 받은 거 아니에요?","JPN":"誰かにプレゼントでもらったんじゃないですか？","ENG":"Perhaps someone gave it to you as a gift?","TWN":"會不會是別人送你的禮物？"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선물이라고? 페스타에서 이런 선물을 받은 적이 있었나?","JPN":"プレゼント？　フェスタでこんなものをもらった覚えはないような……","ENG":"A gift? I don't remember anyone giving out gifts like this at the festival...","TWN":"禮物？我不記得有在慶典裡收到這個禮物？"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럴 수도 있죠. 축제 같은 데 가면, 원래 기념품으로 이것저것 많이 나눠주니까요.","JPN":"まあ、そんな時もあります。\\nそういうところに行くと記念品がもらえることもありますし。","ENG":"It's still possible. Festivals usually hand out various souvenirs, don't they?","TWN":"是有可能的，畢竟去慶典的時候就是會收到很多紀念品。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"나중에 보면…… 대체 이런 걸 왜 받았는지 잊어버리기도 하죠.","JPN":"後で見つけて……\\nなぜこんなものを貰ったのか忘れてしまうこともあります。","ENG":"But later... we all forget why we received them in the first place.","TWN":"但離開後……可能也不記得收到過這種東西。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 저는 그다지 물건에 미련 두지 않는 성격이라서 쓸모없는 물건은 그때그때 처분하는 편이지만요.","JPN":"まあ、僕はあまり物に未練がない性格なので、\\n使い道がない物はその都度処分する主義ですが。","ENG":"For me, I don't get attached to things, so I throw them away if they are of no use to me.","TWN":"不過我個人是沒有蒐集癖，沒用的東西我都會直接斷捨離。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양?","JPN":"ミナさん？","ENG":"Mina?","TWN":"米娜？"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기억이라는 건 어느 날 문득 떠오르기도 하고, 갑자기 잊어버리기도 하잖아?","JPN":"記憶って、ふと思い出したり、急に忘れてしまうことだってあるでしょ？","ENG":"Memories come and go all the time, right?","TWN":"記憶不就是這樣嗎？有時候會突然忘記，有時候又會突然想起來。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 나는 그냥 가지고 있을래.","JPN":"だから私はこのまま保管しておく。","ENG":"So I think I'm gonna keep this one.","TWN":"所以我要留著。"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기억나지 않아도…… 누가 준 건지 몰라도…… 어쩌면 친구들과의 소중한 추억이 담겨있을지도 모르는 일이잖아?","JPN":"思い出せなくても……誰から貰ったのかわからなくても……\\nもしかしたら、友達との大切な思い出が詰まっているかもしれないじゃない？","ENG":"Even if I don't remember why... or who gave it to me... It might hold precious memories with friends, right?","TWN":"即使我想不起來……即使不知道是誰送的……\\n但這裡面或許藏著我和朋友之間寶貴的回憶，不是嗎？"},"stage":{"bg":"GEASS_05","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};